	test(5, strtold("-inf", NULL), 13.37, EDOM, FE_INVALID, nanl(""), nanl(""), nanl(""), 0);
	test(6, 0.0, 13.37, 0, 0, -0x0.000000000000001p-16385L, 0x0.0p+0L, 0x0.000000000000001p-16385L, 0);
	test(7, 90.01, -12.34, 0, 0, 0xe.851eb851eb8bfffp-2L, 0xe.851eb851eb8cp-2L, 0xe.851eb851eb8c001p-2L, 0);
	test(8, -12.34, -12.34, 0, 0, -0x0.000000000000001p-16385L, -0x0.0p+0L, 0x0.000000000000001p-16385L, 0);
	test(9, nanl(""), -12.34, 0, 0, nanl(""), nanl(""), nanl(""), 0);
