	test(13, 90.01, nanl(""), 0, 0, nanl(""), nanl(""), nanl(""), 0);
	test(14, -12.34, nanl(""), 0, 0, nanl(""), nanl(""), nanl(""), 0);
	test(15, nanl(""), nanl(""), 0, 0, nanl(""), nanl(""), nanl(""), 0);
