	test(26, -12.34, strtold("-inf", NULL), 0, 0, -0xc.570a3d70a3d7001p+0L, -0xc.570a3d70a3d7p+0L, -0xc.570a3d70a3d6fffp+0L, 0);
	test(27, nanl(""), strtold("-inf", NULL), 0, 0, nanl(""), nanl(""), nanl(""), 0);
