	test(30, 0.0, strtold("-inf", NULL), 0, 0, -0x0.000000000000001p-16385L, 0x0.0p+0L, 0x0.000000000000001p-16385L, 0);
	test(31, 90.01, 0.0, EDOM, FE_INVALID, nanl(""), nanl(""), nanl(""), 0);
